// @ts-nocheck
let subjectsList=[];async function loadSubjects(){if(currentUser)try{subjectsList=await sbGetSubjects(currentUser.id),refreshAllSubjectDropdowns(),updateSubjectsBadge()}catch(e){console.error("Gagal load subjects:",e)}}function refreshAllSubjectDropdowns(){document.querySelectorAll(".subject-dropdown").forEach(e=>{const t=e.value;e.innerHTML='<option value="">— Pilih mata pelajaran —</option>',subjectsList.forEach(t=>{const n=document.createElement("option");n.value=t.id,n.textContent=t.icon+" "+t.name,e.appendChild(n)}),t&&(e.value=t)})}function updateSubjectsBadge(){const e=document.querySelector("#nav-subjects .sb-badge");e&&(e.textContent=subjectsList.length)}function openAddSubjectModal(e){document.getElementById("modal-add-subject").style.display="flex",document.getElementById("modal-return-dropdown").value=e||"",document.getElementById("new-subject-name").value="",document.getElementById("new-subject-icon").value="📚",setTimeout(()=>document.getElementById("new-subject-name").focus(),100)}function closeAddSubjectModal(){document.getElementById("modal-add-subject").style.display="none"}async function saveNewSubject(){const e=document.getElementById("new-subject-name").value.trim();if(!currentUser)return showToast("Kamu harus login dulu!","error"),void closeAddSubjectModal();const t=document.getElementById("new-subject-icon").value.trim()||"📚",n=document.getElementById("modal-return-dropdown").value;if(!e)return void showToast("Masukkan nama mata pelajaran!","error");const s=document.getElementById("btn-save-subject");s.disabled=!0,s.textContent="Menyimpan...";try{const s=await sbAddSubject(currentUser.id,e,t);if(subjectsList.push(s),refreshAllSubjectDropdowns(),updateSubjectsBadge(),n){const e=document.getElementById(n);e&&(e.value=s.id)}showToast(`"${e}" berhasil ditambahkan!`,"success"),closeAddSubjectModal(),"none"!==document.getElementById("subpage-subjects").style.display&&renderSubjectsPage()}catch(e){showToast("Gagal menambah mata pelajaran: "+e.message,"error")}finally{s.disabled=!1,s.textContent="Simpan"}}async function renderSubjectsPage(){const e=document.getElementById("subjects-grid");if(!e)return;if(!subjectsList.length)return void(e.innerHTML='\n      <div class="subjects-empty">\n        <p>Belum ada mata pelajaran.</p>\n        <button class="btn-primary sm" onclick="openAddSubjectModal()">+ Tambah Pertama</button>\n      </div>');e.innerHTML='<div class="subjects-loading">Memuat...</div>';const t=await Promise.all(subjectsList.map(async e=>{const t=await sbGetTopics(e.id);return{...e,topics:t}}));e.innerHTML="",t.forEach(t=>{const n=document.createElement("div");n.className="subject-card-v2",n.id="subj-card-"+t.id;const s=t.topics.map(e=>`\n      <div class="topic-item" id="topic-${e.id}">\n        <div class="topic-header" onclick="toggleTopic('${e.id}')">\n          <div class="topic-info">\n            <span class="topic-name">${e.name}</span>\n            <span class="topic-date">${formatDate(e.date)}</span>\n          </div>\n          <svg class="topic-arrow" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">\n            <polyline points="6 9 12 15 18 9"/>\n          </svg>\n        </div>\n        <div class="topic-points" id="points-${e.id}" style="display:none">\n          <div class="points-loading">Memuat poin...</div>\n        </div>\n      </div>\n    `).join("");n.innerHTML=`\n      <div class="sc2-header">\n        <div class="sc2-icon">${t.icon}</div>\n        <div class="sc2-info">\n          <div class="sc2-name">${t.name}</div>\n          <div class="sc2-count">${t.topics.length} topik</div>\n        </div>\n        <button class="sc2-delete" onclick="confirmDeleteSubject('${t.id}', '${t.name}')" title="Hapus">\n          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">\n            <polyline points="3 6 5 6 21 6"/>\n            <path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/>\n          </svg>\n        </button>\n      </div>\n      <div class="sc2-topics">\n        ${t.topics.length?s:'<p class="sc2-empty">Belum ada topik tersimpan</p>'}\n      </div>\n    `,e.appendChild(n)})}async function toggleTopic(e){const t=document.getElementById("points-"+e),n=document.querySelector(`#topic-${e} .topic-arrow`);if("none"!==t.style.display)t.style.display="none",n&&(n.style.transform="");else if(t.style.display="block",n&&(n.style.transform="rotate(180deg)"),t.querySelector(".points-loading"))try{const n=await sbGetAiPointsByTopic(e);n.length?t.innerHTML='<ul class="kp-list">'+n.map(e=>`<li><span class="kp-dot"></span>${e.point_text}</li>`).join("")+"</ul>":t.innerHTML='<p class="points-empty">Belum ada poin AI tersimpan untuk topik ini.</p>'}catch(e){t.innerHTML='<p class="points-empty" style="color:var(--red)">Gagal memuat poin.</p>'}}function confirmDeleteSubject(e,t){confirm(`Hapus mata pelajaran "${t}"?\nSemua topik dan poin terkait juga akan terhapus.`)&&deleteSubject(e,t)}async function deleteSubject(e,t){try{await sbDeleteSubject(e),subjectsList=subjectsList.filter(t=>t.id!==e),refreshAllSubjectDropdowns(),updateSubjectsBadge(),renderSubjectsPage(),showToast(`"${t}" berhasil dihapus.`,"success")}catch(e){showToast("Gagal menghapus: "+e.message,"error")}}function filterSubjects(e){const t=document.querySelectorAll(".subject-card-v2"),n=e.toLowerCase();t.forEach(e=>{const t=e.querySelector(".sc2-name")?.textContent.toLowerCase()||"";e.style.display=t.includes(n)?"":"none"})}function formatDate(e){if(!e)return"";return new Date(e+"T00:00:00").toLocaleDateString("id-ID",{day:"numeric",month:"long",year:"numeric"})}function todayISO(){return(new Date).toISOString().split("T")[0]}